                                </div>

                                <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 md:gap-4">
                                    {items.map(item => {
                                        if (item.type === 'achievement') {
                                            const earned = achievements.includes(item.data.id);
                                            return (
                                                <AchievementCard 
                                                    key={item.data.id}
                                                    path={item.data}
                                                    earned={earned}
                                                    onClick={() => {
                                                        if (earned) haptics.tap();
