                                    <m.div
                                        initial={{ scale: 0, opacity: 0 }}
                                        animate={{ scale: [0, 1.2, 1], opacity: 1 }}
                                        transition={{ duration: 0.6, ease: "easeOut" }}
                                        style={{ fontSize: 72, marginBottom: 20, filter: `drop-shadow(0 0 30px ${theme.accent})` }}
                                        className="flex items-center justify-center"
                                    >
                                        {lesson.icon?.startsWith("@") ? (
                                            <div className="w-20 h-20 relative">
                                                <Image 
                                                    src={`/assets/logos/${lesson.icon.substring(1)}`} 
                                                    alt="" 
                                                    fill 
                                                    className="object-contain"
                                                />
                                            </div>
                                        ) : (
                                            lesson.icon || "ΓÜí"
                                        )}
                                    </m.div>

                                    {/* Step 2: Title */}
                                    <m.h2
                                        initial={{ y: 20, opacity: 0 }}
                                        animate={{ y: 0, opacity: 1 }}
                                        transition={{ delay: 0.3 }}
                                        style={{ fontSize: 28, fontWeight: 500, marginBottom: 4 }}
                                    >
                                        ╫⌐╫Ö╫ó╫ò╫¿ ╫ö╫ò╫⌐╫£╫¥! ≡ƒÄë
                                    </m.h2>

                                    {/* Step 3: XP */}
                                    <m.div
                                        initial={{ y: 20, opacity: 0 }}
                                        animate={{ y: 0, opacity: 1 }}
                                        transition={{ delay: 0.6 }}
                                        className="my-8"
                                    >
                                        <div style={{ fontSize: 48, fontWeight: 700, color: "#FCD34D" }}>
                                            <XPCounter target={earnedXp} />
                                        </div>
                                        <p style={{ fontSize: 13, opacity: 0.6, marginTop: 4 }}>XP ╫á╫ò╫í╫ñ╫ò ╫£╫ù╫⌐╫æ╫ò╫á╫Ü</p>
                                    </m.div>

                                    {/* Step 4: Pull quote */}
                                    {lesson.pullQuote && (
                                        <m.div
                                            initial={{ y: 20, opacity: 0 }}
                                            animate={{ y: 0, opacity: 1 }}
                                            transition={{ delay: 1 }}
                                            style={{
                                                maxWidth: 400,
                                                fontSize: 16,
                                                fontStyle: "italic",
                                                color: theme.accent,
                                                borderRight: `2px solid ${theme.accent}`,
                                                paddingRight: 16,
                                                textAlign: "right",
                                                lineHeight: 1.7,
                                                marginBottom: 32,
                                            }}
                                        >
                                            {lesson.pullQuote}
                                        </m.div>
                                    )}

                                    {/* Step 5: CTAs */}
                                    <m.div
                                        initial={{ y: 20, opacity: 0 }}
                                        animate={{ y: 0, opacity: 1 }}
                                        transition={{ delay: 1.4 }}
                                        className="w-full max-w-[320px] space-y-3"
                                    >
                                        {nextLesson ? (
                                            <m.button
                                                whileTap={{ scale: 0.95 }}
                                                onClick={() => router.replace(`/lesson/${nextLesson.id}?from=${from ?? 'home'}`)}
