                            <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 bg-yellow-500 text-black text-[8px] font-black px-2 py-0.5 rounded-full whitespace-nowrap shadow-lg">
                                ╫ö╫Ö╫⌐╫Æ ╫æ╫₧╫í╫£╫ò╫£
                            </div>
                        </div>
                    </m.div>
                )}
            </AnimatePresence>

            {/* Course Card */}
            <Link 
