                        </div>

                        <div>
                            <div className="flex items-center gap-3 mb-2">
                                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">╫¬╫ù╫á╫ö {index + 1}</span>
                                {isCompleted && <span className="text-[10px] font-black text-green-500 uppercase tracking-[0.2em]">╫ö╫ò╫⌐╫£╫¥</span>}
